class Solution:
    def countBinaryPalindromes(self, n):
        if n < 0:
            return 0
        count = 1
        for L in range(1, 51):
            if (1 << (L - 1)) > n:
                break
            half = (L + 1) // 2
            lo = 1 << (half - 1)
            def pal_val(p):
                s = bin(p)[2:]
                full = s + s[::-1] if L % 2 == 0 else s + s[-2::-1]
                return int(full, 2)
            if n >= (1 << L):
                hi = (1 << half) - 1
                count += hi - lo + 1
                continue
            cand = n >> (L - half)
            if cand < lo:
                continue
            if pal_val(cand) <= n:
                count += cand - lo + 1
            else:
                count += cand - lo
        return count

