class Solution:
    def countBinaryPalindromes(self, n):
        if n < 0:
            return 0
        count = 1
        for L in range(1, 51):
            if (1 << (L - 1)) > n:
                break
            half = (L + 1) // 2
            lo = 1 << (half - 1)
            hi = (1 << half) - 1
            def pal_val(p):
                s = bin(p)[2:]
                full = s + s[::-1] if L % 2 == 0 else s + s[-2::-1]
                return int(full, 2)
            if pal_val(lo) > n:
                continue
            a, b = lo, hi
            while a < b:
                mid = (a + b + 1) // 2
                if pal_val(mid) <= n:
                    a = mid
                else:
                    b = mid - 1
            count += a - lo + 1
        return count

