var countBinaryPalindromes = function(n) {
    n = BigInt(n);
    if (n < 0n) return 0;
    let count = 1n;
    for (let L = 1; L <= 50; L++) {
        const Lb = BigInt(L);
        if ((1n << (Lb - 1n)) > n) break;
        const half = Math.floor((L + 1) / 2);
        const hb = BigInt(half);
        const lo = 1n << (hb - 1n);
        const hi = (1n << hb) - 1n;
        const palVal = (p) => {
            const s = p.toString(2);
            let full;
            if (L % 2 === 0) full = s + s.split('').reverse().join('');
            else full = s + s.slice(0, -1).split('').reverse().join('');
            return BigInt('0b' + full);
        };
        if (palVal(lo) > n) continue;
        let a = lo, b = hi;
        while (a < b) {
            const mid = (a + b + 1n) / 2n;
            if (palVal(mid) <= n) a = mid;
            else b = mid - 1n;
        }
        count += a - lo + 1n;
    }
    return Number(count);
};
